{
  "name": "FonoAI - Asistente de Transcripción Clínica",
  "description": "Una plataforma para fonoaudiólogos que transcribe grabaciones de pacientes con alta fidelidad y genera análisis clínicos preliminares utilizando IA para identificar patrones de habla y áreas de mejora."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import LoginPage from './pages/LoginPage';
import DashboardLayout from './pages/DashboardLayout';
import DashboardPage from './pages/DashboardPage';
import PatientsPage from './pages/PatientsPage';
import NewEvaluationPage from './pages/NewEvaluationPage';
import LandingPage from './pages/LandingPage';
import type { User } from './types';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);

  const handleLogin = (loggedInUser: User) => {
    setUser(loggedInUser);
  };

  const handleLogout = () => {
    setUser(null);
  };

  return (
    <HashRouter>
      <Routes>
        <Route path="/" element={!user ? <LandingPage /> : <Navigate to="/dashboard" />} />
        <Route path="/login" element={!user ? <LoginPage onLogin={handleLogin} /> : <Navigate to="/dashboard" />} />

        <Route 
          path="/*"
          element={
            user ? (
              <Routes>
                <Route path="/dashboard" element={<DashboardLayout user={user} onLogout={handleLogout}><DashboardPage /></DashboardLayout>} />
                <Route path="/patients" element={<DashboardLayout user={user} onLogout={handleLogout}><PatientsPage /></DashboardLayout>} />
                <Route path="/new-evaluation" element={<DashboardLayout user={user} onLogout={handleLogout}><NewEvaluationPage /></DashboardLayout>} />
                <Route path="*" element={<Navigate to="/dashboard" />} />
              </Routes>
            ) : (
              <Navigate to="/login" />
            )
          }
        />
      </Routes>
    </HashRouter>
  );
};

export default App;

export interface User {
  name: string;
