                            </svg>
                            Procesando...
                        </>
                    ) : 'Subir y Procesar'}
                </button>
            </form>

            {(transcription || analysis) && (
                <div className="mt-10 bg-white p-6 rounded-lg shadow-md space-y-6">
                    <h2 className="text-2xl font-bold text-gray-800">Resultados del Análisis</h2>
