import React, { useState, useCallback } from 'react';

interface FileUploadProps {
    onFileChange: (file: File | null) => void;
}

const FileUpload: React.FC<FileUploadProps> = ({ onFileChange }) => {
    const [fileName, setFileName] = useState<string | null>(null);
    const [isDragOver, setIsDragOver] = useState(false);

    const handleFile = useCallback((file: File | null) => {
        if (file && file.type.startsWith('video/')) {
            setFileName(file.name);
            onFileChange(file);
        } else {
            setFileName(null);
            onFileChange(null);
            // Optionally show an error message
            alert("Por favor, selecciona un archivo de video válido.");
        }
    }, [onFileChange]);

    const handleDragEnter = (e: React.DragEvent<HTMLLabelElement>) => {
        e.preventDefault();
        e.stopPropagation();
        setIsDragOver(true);
    };

    const handleDragLeave = (e: React.DragEvent<HTMLLabelElement>) => {
        e.preventDefault();
        e.stopPropagation();
        setIsDragOver(false);
    };

    const handleDragOver = (e: React.DragEvent<HTMLLabelElement>) => {
        e.preventDefault();
        e.stopPropagation();
    };

    const handleDrop = (e: React.DragEvent<HTMLLabelElement>) => {
        e.preventDefault();
        e.stopPropagation();
        setIsDragOver(false);
        const files = e.dataTransfer.files;
        if (files && files.length > 0) {
            handleFile(files[0]);
        }
    };

    const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const files = e.target.files;
        if (files && files.length > 0) {
            handleFile(files[0]);
        }
    };

    return (
        <div>
            <label
                onDragEnter={handleDragEnter}
                onDragLeave={handleDragLeave}
                onDragOver={handleDragOver}
                onDrop={handleDrop}
                className={`flex justify-center w-full h-48 px-4 transition bg-white border-2 ${isDragOver ? 'border-indigo-500 bg-indigo-50' : 'border-gray-300'} border-dashed rounded-md appearance-none cursor-pointer hover:border-gray-400 focus:outline-none`}>
                <span className="flex items-center space-x-2">
                     <svg xmlns="http://www.w3.org/2000/svg" className="w-8 h-8 text-gray-600" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
                        <path strokeLinecap="round" strokeLinejoin="round" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
                    </svg>
                    <span className="font-medium text-gray-600">
                        Arrastra un video o{' '}
                        <span className="text-indigo-600 underline">haz clic para seleccionar</span>
                    </span>
                </span>
                <input type="file" name="file_upload" className="hidden" accept="video/mp4,video/quicktime,video/x-msvideo,video/x-matroska,video/webm" onChange={handleChange} />
            </label>
            <p className="text-sm text-center text-gray-500 mt-2">Soporta MP4, MOV, AVI, MKV, WebM (hasta 400MB)</p>
            {fileName && (
                <div className="mt-4 p-3 bg-gray-100 rounded-lg text-sm text-gray-700 flex justify-between items-center">
                    <span>{fileName}</span>
                    <button onClick={() => { setFileName(null); onFileChange(null); }} className="text-red-500 hover:text-red-700">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                            <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
                        </svg>
                    </button>
                </div>
            )}
        </div>
    );
};

